import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"94. Contractors And Labour Hire","description":"","frontmatter":{"title":"94. Contractors And Labour Hire","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/94-contractors-and-labour-hire.md","filePath":"ebas/allied-health/classification-staffing/94-contractors-and-labour-hire.md"}'),s={name:"ebas/allied-health/classification-staffing/94-contractors-and-labour-hire.md"};function n(i,e,l,p,c,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_94-contractors-and-labour-hire" tabindex="-1">94. Contractors And Labour Hire <a class="header-anchor" href="#_94-contractors-and-labour-hire" aria-label="Permalink to &quot;94. Contractors And Labour Hire&quot;">​</a></h1><p><strong>94.1</strong> The Employer acknowledges the positive impact that secure employment has on employees and the provision of quality services to the Victorian community and will give preference to engaging people to perform work covered by this Agreement as Employees, rather than engaging:</p><p><strong>(a)</strong> contractors (including contractors that are employees of the Employer);</p><p><strong>(b)</strong> employees of contractors (including employees of contractors that are employees of the Employer); and</p><p><strong>(c)</strong> employees of labour hire businesses; to perform such work.</p><p><strong>94.2</strong> The BPECC will design a survey for Employers to complete to identify the following in relation to the people referred to at subclauses 94.1(a) to (c):</p><p><strong>(a)</strong> how many such people perform work at the Employer;</p><p><strong>(b)</strong> the professions they perform work at the Employer;</p><p><strong>(c)</strong> the sites such people perform work at the Employer;</p><p><strong>(d)</strong> the gender breakdown of such people;</p><p><strong>(e)</strong> at approximately what grades/levels/classes under the Agreement do such people perform work; and</p><p><strong>(f)</strong> anything else agreed by BPECC.</p><p><strong>94.3</strong> The Employer recognises that engaging the people referred to at 94.1(a) to (c) above to perform work covered by this Agreement, other than on a short-term basis, will generally be a Major Change as defined at <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> and therefore may require consultation.</p>',13)])])}const m=o(s,[["render",n]]);export{g as __pageData,m as default};
